import{_ as a,o as i,c as g,a2 as u}from"./chunks/framework.M-AdQQii.js";const d=JSON.parse('{"title":"1.7星期限定活动","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 星期限定活动指的是，只能在指定星期数进行接取和提交任务的活动。 该类活动在接取后会有一个24 小时的时间限制，需要在24 小时内完成该任务。 例如，你可以在周二早上11：30 接取周一的跑","frontmatter":{"title":"1.7星期限定活动","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 星期限定活动指的是，只能在指定星期数进行接取和提交任务的活动。 该类活动在接取后会有一个24 小时的时间限制，需要在24 小时内完成该任务。 例如，你可以在周二早上11：30 接取周一的跑","outline":"deep"},"headers":[],"relativePath":"life/1-7.md","filePath":"life/1-7.md","lastUpdated":1782387794000}'),e={name:"life/1-7.md"};function t(l,s,r,p,o,f){return i(),g("div",null,[...s[0]||(s[0]=[u('<h1 id="_1-7星期限定活动" tabindex="-1">1.7星期限定活动 <a id="s089-c4e8f80f"></a> <a class="header-anchor" href="#_1-7星期限定活动" aria-label="Permalink to &quot;1.7星期限定活动 &lt;a id=&quot;s089-c4e8f80f&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_1-7-1-什么是星期限定活动" tabindex="-1">1.7.1 什么是星期限定活动 <a id="s090-05d58571"></a> <a class="header-anchor" href="#_1-7-1-什么是星期限定活动" aria-label="Permalink to &quot;1.7.1 什么是星期限定活动 &lt;a id=&quot;s090-05d58571&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>星期限定活动指的是，只能在指定星期数进行接取和提交任务的活动。</p><p>该类活动在接取后会有一个24 小时的时间限制，需要在24 小时内完成该任务。</p><p>例如，你可以在周二早上11：30 接取周一的跑黑炭任务，然后在当天下午完成任务。</p><p>但是交任务获取奖励需要等到下一个周一。但是这样子你下次周一就不能再接取该任务，只能下下周再接取这个任务。</p><p>该类活动大部分可以在光芒海岸烟飨之庭附近NPC 处或者主城喷泉NPC 处接取和提交任务。</p><h2 id="_1-7-2-周一跑黑色源晶精华-黑炭-任务" tabindex="-1">1.7.2 周一跑黑色源晶精华（黑炭）任务 <a id="s091-798a748d"></a> <a class="header-anchor" href="#_1-7-2-周一跑黑色源晶精华-黑炭-任务" aria-label="Permalink to &quot;1.7.2 周一跑黑色源晶精华（黑炭）任务 &lt;a id=&quot;s091-798a748d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>周一可以在光芒烟飨之庭副本右边，或者主城看到以下NPC：</p><p>3 个阶段任务分别需要交7、14、28 包交易品，只有是获得的黑炭的，不管是东大西大对跑还是原大陆来回跑都能完成任务，是不是自己买的货对完成任务没有影响，</p><p>也就是说你可以让家族里一直跑黑炭的人货给你交做任务，你给他黑炭帮他节约劳动力。同样你打劫来的货一样可以完成任务。</p><p>3 个阶段任务和提交3 个阶段任务的任务奖励如下：</p><p>1 和2 阶段任务奖励箱子内容如图：</p><p>3 阶段任务奖励箱子内容如图：</p><p>最后一个蓝色的是随机赛艇装备图纸宝箱，如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1225.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1233.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1234.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1235.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1236.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1241.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1242.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1243.jpeg" alt="图示：1.7.2 周一跑黑色源晶精华（黑炭）任务" loading="lazy"></figure><h2 id="_1-7-3-周二、六出海钓大鱼任务" tabindex="-1">1.7.3 周二、六出海钓大鱼任务 <a id="s092-83cee0f7"></a> <a class="header-anchor" href="#_1-7-3-周二、六出海钓大鱼任务" aria-label="Permalink to &quot;1.7.3 周二、六出海钓大鱼任务 &lt;a id=&quot;s092-83cee0f7&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>在每周二、六你可以在光芒烟飨之庭副本右边，或者主城看到以下NPC：</p><p>对话后接取5 阶段钓鱼任务。</p><p>该任务如题所言，必须是出海钓大鱼并交了才能完成，淡水大鱼不能完成任务。</p><p>这个任务不管是在哪、谁钓上来的、哪个贩鱼台交的，只要是你交了就完成任务。</p><p>任务内容如下图：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1248.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1249.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1250.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1256.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1257.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1258.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1259.jpeg" alt="图示：1.7.3 周二、六出海钓大鱼任务" loading="lazy"></figure><h2 id="_1-7-4-周三挖宝箱、沉船、藏宝图任务" tabindex="-1">1.7.4 周三挖宝箱、沉船、藏宝图任务 <a id="s093-afe1e320"></a> <a class="header-anchor" href="#_1-7-4-周三挖宝箱、沉船、藏宝图任务" aria-label="Permalink to &quot;1.7.4 周三挖宝箱、沉船、藏宝图任务 &lt;a id=&quot;s093-afe1e320&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="任务流程" tabindex="-1">任务流程 <a id="s094-57c6ac52"></a> <a class="header-anchor" href="#任务流程" aria-label="Permalink to &quot;任务流程 &lt;a id=&quot;s094-57c6ac52&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>每周三重置后在光芒烟飨之庭副本右边，或者主城刷新任务NPC，NPC 如下图：</p><p>任务内容如下：</p><p>注意事项：沉船宝箱任务每阶段计分规则是不一样的，本攻略以完成5 阶段的计分标准来记述。</p><p>在探险熟练度达标的情况下，一船沉船为16 包货=48 积分，即1 包货=3 积分，</p><p>要挖上3 船沉船才能完成5 阶段任务，不过你可以重置前就开始找沉船，挖好后去光芒海岸，然后跳门去接取该系列任务再跳门回来交货。</p><p>在挖海底宝箱的情况下，必须先接取任务，一个宝箱=9 积分，需要16 个宝箱才能做完5 阶段任务。挖一个宝箱会有一个debuff，2 分钟内不能挖下一个宝箱。</p><p>DEBUFF 如图所示：</p><p>改版后藏宝图也能增加分数，蓝色藏宝图不加分，紫色藏宝图挖出后给6 分。</p><p>上图道具为随机盲盒，会出强化卷轴、冥界石头、buff 等。</p><p>上图为全任务完成奖励盒子，最下面蓝色的是随机赛艇装备图纸包裹。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1266.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1267.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1268.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1273.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1274.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1275.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1276.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1281.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1282.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1283.jpeg" alt="图示：任务流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1284.jpeg" alt="图示：任务流程" loading="lazy"></figure><h3 id="只做1阶段-搞海战币" tabindex="-1">只做1阶段（搞海战币） <a id="s095-0fc1d65a"></a> <a class="header-anchor" href="#只做1阶段-搞海战币" aria-label="Permalink to &quot;只做1阶段（搞海战币） &lt;a id=&quot;s095-0fc1d65a&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>只需要挖8 个海底宝箱即可完成一阶段任务拿到海战币。</p><h3 id="鱼币-分类为水产品-兑换道具" tabindex="-1">鱼币（分类为水产品）兑换道具 <a id="s096-f59f07a6"></a> <a class="header-anchor" href="#鱼币-分类为水产品-兑换道具" aria-label="Permalink to &quot;鱼币（分类为水产品）兑换道具 &lt;a id=&quot;s096-f59f07a6&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>进入幻想岛后右转，找到以下兑换机：</p><p>这里面可以兑换的东西非常多，建议使用搜搜功能，方法如下：</p><p>先鼠标右键红色箭头①指向的材料，再在红色框里输入gold，再鼠标右键点击蓝</p><p>色箭头指向的搜索。如下图：</p><p>搜索后，第二个栏目即是可以兑换的内容，如下：</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1289.jpeg" alt="图示：鱼币（分类为水产品）兑换道具" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1290.jpeg" alt="图示：鱼币（分类为水产品）兑换道具" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1297.jpeg" alt="图示：鱼币（分类为水产品）兑换道具" loading="lazy"></figure><h2 id="_1-7-6-周五前往自由岛跑稳定的龙骨精华任务" tabindex="-1">1.7.6 周五前往自由岛跑稳定的龙骨精华任务 <a id="s097-822ac44d"></a> <a class="header-anchor" href="#_1-7-6-周五前往自由岛跑稳定的龙骨精华任务" aria-label="Permalink to &quot;1.7.6 周五前往自由岛跑稳定的龙骨精华任务 &lt;a id=&quot;s097-822ac44d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>周五的跑龙骨任务和周一的跑黑炭任务一样，不管是哪买的谁买的货，只要是你交到自由岛的卖龙骨NPC 就能完成任务。</p><p>龙骨3 阶段任务和提交3 个任务的任务奖励如图：</p><p>3 阶段任务奖励宝箱内容如图：</p><p>随机赛艇图纸如下:</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1302.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1303.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1304.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1305.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1311.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1312.jpeg" alt="图示：1.7.6 周五前往自由岛跑稳定的龙骨精华任务" loading="lazy"></figure><h2 id="_1-7-7周六跑内陆货任务" tabindex="-1">1.7.7周六跑内陆货任务 <a id="s098-c349c7b8"></a> <a class="header-anchor" href="#_1-7-7周六跑内陆货任务" aria-label="Permalink to &quot;1.7.7周六跑内陆货任务 &lt;a id=&quot;s098-c349c7b8&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>周六可以在光芒烟飨之庭副本右边，或者主城看到以下NPC：</p><p>他的任务是让你跑28 包金币货，不</p><p>管是普通货、星星货、肥料货、发酵货等</p><p>都是可以完成任务的。同样的该任务对制</p><p>作人也没有要求，你只需要交28 包货，</p><p>即可获得45 露露币</p><p>跑完28 包货后找</p><p>该NPC 提交任务即可获得45 个鲁鲁币。</p><p>冷知识：这个任务你可以换角色接着做，以此换取大量鲁鲁币，因为鲁鲁币是账号共享，但是每个角色的任务是单独的。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1318.jpeg" alt="图示：1.7.7周六跑内陆货任务" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1319.jpeg" alt="图示：1.7.7周六跑内陆货任务" loading="lazy"></figure><h2 id="_1-7-8-周日早上幻想岛钓鱼大赛" tabindex="-1">1.7.8 周日早上幻想岛钓鱼大赛 <a id="s099-be1684eb"></a> <a class="header-anchor" href="#_1-7-8-周日早上幻想岛钓鱼大赛" aria-label="Permalink to &quot;1.7.8 周日早上幻想岛钓鱼大赛 &lt;a id=&quot;s099-be1684eb&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h3 id="参与流程" tabindex="-1">参与流程 <a id="s100-5669e3a8"></a> <a class="header-anchor" href="#参与流程" aria-label="Permalink to &quot;参与流程 &lt;a id=&quot;s100-5669e3a8&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>幻想岛钓鱼大赛开启时间为周日早上00：00，结束时间为中午12：00.</p><p>可以在幻想岛如下位置接取任务：</p><p>靠近这个NPC 接取任务后会给一个钓竿（性能特别垃圾），后续钓鱼流程和正常钓大鱼一样，不过幻想岛钓大鱼只会出粉红枪鱼，按长度计算排名，最长的是幸运的粉红枪鱼。</p><p>卖鱼位置如下：</p><p>幻想岛钓大鱼排名高会有蓝颜贝奖励，不同名次都会有币奖励，幻想岛钓鱼币可以换加钓鱼熟练度的饰品和装备。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1326.jpeg" alt="图示：参与流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1327.jpeg" alt="图示：参与流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1334.jpeg" alt="图示：参与流程" loading="lazy"></figure><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1335.jpeg" alt="图示：参与流程" loading="lazy"></figure><h3 id="幻想岛钓鱼币兑换道具" tabindex="-1">幻想岛钓鱼币兑换道具 <a id="s101-5b9e65b8"></a> <a class="header-anchor" href="#幻想岛钓鱼币兑换道具" aria-label="Permalink to &quot;幻想岛钓鱼币兑换道具 &lt;a id=&quot;s101-5b9e65b8&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>进入幻想岛后右转找到下图NPC 即可：</p><p>冷知识：获取/消耗排名币兑换也是这个NPC。</p><figure class="image-flow"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1340.jpeg" alt="图示：幻想岛钓鱼币兑换道具" loading="lazy"></figure>',111)])])}const h=a(e,[["render",t]]);export{d as __pageData,h as default};
